parameters.jsCode:
const lead = $('Pick lead + claim').first().json;
if (!lead || !lead.lead_id) {
  return { json: { __no_work__: true, reason: 'no lead ready for marketing' } };
}
const body = $('Trigger').first().json.body || {};

const leadEmail = (lead.email && lead.email.trim()) ? lead.email.trim() : null;
const hasValidEmail = !!leadEmail;
const dry_run = (body.dry_run === true) || !hasValidEmail;
const adminEmail = $env.BRIDGE_ADMIN_EMAIL || 'bridge.digital.solution@gmail.com';
const to_email = dry_run ? adminEmail : leadEmail;

// Prompt: generate a short, honest B2B cold email. HAIKU-sized.
const sys = "You write short UK B2B outreach emails for Bridge Digital "
  + "Solution. Every email: (1) opens warmly addressing the business owner, "
  + "(2) explains we built a no-commitment demo website based on their "
  + "public info, (3) includes the demo URL, (4) invites them to reply by "
  + "email or WhatsApp/phone, (5) ends with a polite one-line opt-out. No "
  + "hype, no promises about rank/traffic, no fabricated testimonials. "
  + "Return ONLY a single JSON object {\"subject\":\"<=70 chars\","
  + "\"body\":\"plain-text body, 100-220 words, uses \\n for line breaks\"}. "
  + "No markdown, no code fences.";

const userFacts = "BUSINESS: " + lead.business_name
  + " | CATEGORY: " + (lead.category || 'service')
  + " | CITY: " + (lead.city || '')
  + " | CURRENT_WEBSITE: " + (lead.website_url_found || 'none')
  + " | RATING: " + (lead.reviews_rating ?? 'null')
  + " | REVIEWS: " + (lead.reviews_count ?? 0)
  + " | DEMO_URL: " + (lead.demo_preview_url || 'none')
  + " | SENDER_NAME: Gelson at Bridge Digital Solution"
  + " | REPLY_TO: bridge.digital.solution@gmail.com"
  + " | WHATSAPP: +44 7345 787028";

return { json: {
  ...lead,
  to_email,
  dry_run,
  hasValidEmail,
  llm_request: {
    message: sys + " FACTS: " + userFacts,
    model: 'HAIKU',
    session_id: 'bridge-email-' + lead.lead_id,
  }
}};

// Parse LLM output, compute expense, prepare Gmail send payload.
const prev = $('Build email request').first().json;
const api = $json;

let parsed = null;
let parseError = null;
try {
  const raw = (api.response || '').trim()
    .replace(/^```json\s*/, '').replace(/```$/, '').trim();
  parsed = JSON.parse(raw);
} catch (e) { parseError = e.message; }

// Fallback — honest, facts-only body.
function fallback() {
  const biz = prev.business_name || 'your business';
  const demo = prev.demo_preview_url || '';
  const city = prev.city || '';
  const subject = `Demo website for ${biz}`;
  const body = [
    `Hi ${biz} team,`,
    ``,
    `I put together a quick demo website based on the public info about ${biz}`,
    city ? `in ${city}. No commitment — just something to look at:` : `. No commitment — just something to look at:`,
    demo || '(preview pending)',
    ``,
    `If it looks useful, reply to this email or ping me on WhatsApp at +44 7345 787028`,
    `and I'll walk you through pricing and timelines.`,
    ``,
    `If not, no worries — reply with "no thanks" and I won't follow up.`,
    ``,
    `Gelson`,
    `Bridge Digital Solution`,
    `bridge.digital.solution@gmail.com`,
  ].join('\n');
  return { subject, body, __fallback__: true, __fallback_reason__: parseError || 'empty' };
}

const email = parsed || fallback();
if (prev.dry_run) {
  email.subject = '[DRY-RUN] ' + email.subject;
  email.body = '[DRY-RUN — would have gone to ' + (prev.hasValidEmail ? prev.email : '(no lead email)') + ']\n\n' + email.body;
}

// Rough token-based cost estimate (Anthropic HAIKU 2026-04: $0.80/M in, $4/M out)
const chars_in  = (JSON.stringify(prev.llm_request) || '').length;
const chars_out = (api.response || '').length;
const input_tokens  = Math.ceil(chars_in / 4);
const output_tokens = Math.ceil(chars_out / 4);
const llm_cost_usd = Number(((input_tokens * 0.80 + output_tokens * 4) / 1_000_000).toFixed(4));

return { json: {
  ...prev,
  subject: email.subject,
  body: email.body,
  llm_cost_usd,
  llm_meta: { input_tokens, output_tokens, model: api.model_used || 'HAIKU', fallback: email.__fallback__ === true }
}};

// Gmail send node returns the message object with id + threadId on success.
// With neverError true, a failure lands here too — detect by checking id.
const prev = $('Parse email + compute cost').first().json;
const resp = $json || {};

const send_ok = !!(resp.id || resp.messageId);
const provider_message_id = resp.id || resp.messageId || null;
const thread_id = resp.threadId || null;

return { json: { ...prev, send_ok, provider_message_id, thread_id, send_raw: resp } };

